class Solution {
public:
    string maximumBinaryString(string binary) {
        int n = binary.size();
        int zeros = 0;
        for (char c : binary) {
            if (c == '0') zeros++;
        }
        if (zeros == 0) return binary;
        string result(n, '1');
        result[n - zeros] = '0';
        return result;
    }
};
```
